# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import kotlinx.android.synthetic.main.activity_share.*

class ShareActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share)

        val intent = intent
        if (intent.action == Intent.ACTION_SEND) {
            handleShareIntent(intent)
        }
    }

    private fun handleShareIntent(intent: Intent) {
        when (intent.type) {
            "text/plain" -> {
                val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
                tv_shared_text.text = sharedText
            }
            "image/*" -> {
                val imageUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
                iv_shared_image.setImageURI(imageUri)
            }
        }
    }

    override fun onCreateOptionsMenu(menu: android.view.Menu): Boolean {
        menuInflater.inflate(R.menu.menu_share, menu)
        return true
    }
}

<?xml version="1.0" encoding="utf-8"?>
<manifest xmlns:android="http://schemas.android.com/apk/res/android"
    package="com.example.app">

    <activity
        android:name=".ShareActivity"
        android:exported="true">
        <intent-filter>
            <action android:name="android.intent.action.SEND" />
            <category android:name="android.intent.category.DEFAULT" />
            <data android:mimeType="text/plain" />
            <data android:mimeType="image/*" />
        </intent-filter>
    </activity>

</manifest>